    def _sort_palette(self, sort_palette, mode, palette_data, colors):
        channels = len(mode)

        if sort_palette == "luminance":

            def sort_key(color):
                r, g, b = color[0], color[1], color[2]
                return r * 299 + g * 587 + b * 114

        elif sort_palette == "rgb":

            def sort_key(color):
                return color

        else:
            raise ValueError("sort_palette must be 'luminance' or 'rgb'")

        def color_at(index):
            return tuple(palette_data[index * channels : (index + 1) * channels])

        used_slots = sorted(index for _count, index in self.getcolors(colors))
        used_colors = [color_at(index) for index in used_slots]
        order = sorted(range(len(used_slots)), key=lambda i: sort_key(used_colors[i]))

        new_palette_data = bytearray(palette_data)
        mapping = list(range(256))
        for new_position, old_position in enumerate(order):
            slot = used_slots[new_position]
            new_palette_data[slot * channels : (slot + 1) * channels] = used_colors[
                old_position
            ]
            mapping[used_slots[old_position]] = slot

        im = self.point(mapping)
        im.palette = ImagePalette.ImagePalette(mode, bytes(new_palette_data))
        return im"}

